def ordinal(n):
    if n < 0:
        raise ValueError("Input must be non-negative")
    if n % 100 in [11, 12, 13]:
        return f"{n}th"
    elif n % 10 == 1:
        return f"{n}st"
    elif n % 10 == 2:
        return f"{n}nd"
    elif n % 10 == 3:
        return f"{n}rd"
    else:
        return f"{n}th"

