class Scheduler:
    def __init__(self):
        self.events = []

    def book(self, start, end, name):
        if start >= end:
            raise ValueError("Start must be less than end")

        for event in self.events:
            if event[0] <= end and event[1] >= start:
                return False

        self.events.append((start, end, name))
        return True

    def cancel(self, name):
        for i, event in enumerate(self.events):
            if event[2] == name:
                del self.events[i]
                return True
        return False

    def next_event(self, t):
        for event in sorted(self.events, key=lambda x: x[0]):
            if event[0] >= t:
                return event[2]
        return None

    def count(self):
        return len(self.events)
