class Warehouse:
    def __init__(self):
        self.stock = {}
        self.reservations = {}

    def add(self, sku, qty):
        if not isinstance(qty, int) or qty <= 0:
            raise ValueError("Quantity must be a positive integer.")
        self.stock.setdefault(sku, 0)
        self.stock[sku] += qty

    def available(self, sku):
        return self.stock.get(sku, 0) - self.reservations.get(sku, 0)

    def reserve(self, sku, qty):
        if sku not in self.stock:
            raise KeyError(f"Sku {sku} not found.")
        if qty <= 0:
            return False
        available = self.available(sku)
        if available < qty:
            return False
        self.reservations.setdefault(sku, 0)
        self.reservations[sku] += qty
        return True

    def release(self, sku, qty):
        if sku not in self.reservations:
            return False
        if qty > self.reservations[sku]:
            qty = self.reservations[sku]
        self.reservations[sku] -= qty
        return True

    def ship(self, sku, qty):
        if sku not in self.stock or sku not in self.reservations:
            return False
        if self.reservations[sku] < qty:
            return False
        self.reservations[sku] -= qty
        self.stock[sku] -= qty
        return True
